2	// TDD RED PHASE: Tests written FIRST, stubs throw NotImplementedException
3	// Run with: dotnet run tests.cs
4	//
5	// TDD Cycle:
6	//   RED   → tests written first, stubs throw → all fail
7	//   GREEN → implement to make tests pass
8	//   REFACTOR → clean up while keeping tests green
9	//
10	// NOTE: In C# file-based apps, top-level statements must come first.
11	// Type/class declarations appear at the bottom of this file.
12	// ============================================================
13	
14	using System;
15	using System.Collections.Generic;
16	using System.IO;
17	using System.Linq;
18	using System.Text;
19	
20	// ===== SIMPLE TEST RUNNER (top-level code, must come first) =====
21	
22	int passed = 0, failed = 0;
23	var failures = new List<string>();
24	
25	void Check(string name, bool condition, string? details = null)
26	{
27	    if (condition)
28	    {
29	        Console.WriteLine($"  [PASS] {name}");
30	        passed++;
31	    }
32	    else
33	    {
34	        var msg = details != null ? $"{name} — {details}" : name;
35	        Console.WriteLine($"  [FAIL] {msg}");
36	        failures.Add(msg);
37	        failed++;
38	    }
39	}
40	
41	void Suite(string title, Action body)
42	{
43	    Console.WriteLine($"\n{title}");
44	    Console.WriteLine(new string('─', title.Length));
45	    try { body(); }
46	    catch (NotImplementedException ex)
47	    {
48	        Console.WriteLine($"  [FAIL] Not implemented: {ex.Message}");
49	        failures.Add($"{title}: {ex.Message}");
50	        failed++;
51	    }
52	    catch (Exception ex)
53	    {
54	        Console.WriteLine($"  [ERROR] Unexpected: {ex.GetType().Name}: {ex.Message}");
55	        failures.Add($"{title}: {ex.Message}");
56	        failed++;
57	    }
58	}
