60	// ===== TEST SUITES =====
61	
62	Console.WriteLine("CSV Report Generator — Test Suite");
63	Console.WriteLine(new string('═', 40));
64	
65	// ── Test 1: CSV Parsing from string ─────────────────────────
66	Suite("Test 1: CSV Parsing from string", () =>
67	{
