69	        name,department,salary,hire_date,status
70	        Alice Johnson,Engineering,95000,2020-03-15,Active
71	        Bob Smith,Marketing,72000,2019-07-22,Inactive
72	        Carol White,Engineering,88000,2021-01-10,Active
73	        """;
74	
75	    var employees = CsvParser.ParseFromString(csv);
76	
77	    Check("Parses 3 rows", employees.Count == 3, $"got {employees.Count}");
78	    Check("Name parsed correctly", employees[0].Name == "Alice Johnson");
79	    Check("Department parsed correctly", employees[0].Department == "Engineering");
80	    Check("Salary parsed as decimal", employees[0].Salary == 95000m);
81	    Check("HireDate parsed correctly", employees[0].HireDate == new DateOnly(2020, 3, 15));
82	    Check("Status Active parsed", employees[0].Status == "Active");
