87	// ── Test 2: CSV Parsing from file ───────────────────────────
88	Suite("Test 2: CSV Parsing from file", () =>
89	{
90	    var tmpFile = Path.ChangeExtension(Path.GetTempFileName(), ".csv");
91	    try
92	    {
